// --- COMPONENT CHÍNH ---
const MaleBack: React.FC<BodyMapProps> = ({ selectedBodyPart, onSelectBodyPart, className }) => {
    const [hoveredPart, setHoveredPart] = useState<string | null>(null);
    const [selectedPart, setSelectedPart] = useState<BodyPart | null>(null);

    const closePopup = () => setSelectedPart(null);

    return (
        <div style={containerStyle}>
            <svg
                viewBox="0 0 168 320"
                xmlns="http://www.w3.org/2000/svg"
                style={{ width: 'auto', height: '100%', maxHeight: '540px' }}
            >
                {/* 1. Các phần tương tác (Group 1) */}
                <g>
                    {BODY_PARTS.map((part) => (
                        <path
                            key={part.id}
                            id={part.id}
                            d={part.d}
                            fill={selectedBodyPart === part.name || selectedBodyPart === part.id ? '#155DFC' : (hoveredPart === part.id ? '#99CCFF' : 'transparent')}
                            fillRule="evenodd"
                            clipRule="evenodd"
                            onMouseEnter={() => setHoveredPart(part.id)}
                            onMouseLeave={() => setHoveredPart(null)}
                            onClick={() => { setSelectedPart(part); onSelectBodyPart?.(part.name); }}
                            style={{ cursor: 'pointer', transition: 'fill 0.2s ease-in-out' }}
                        />
                    ))}
                </g>

                {/* 2. Đường viền tĩnh Outline (Group 2) */}
                <g id="outline" style={{ pointerEvents: 'none' }}>
                    {OUTLINES.map((pathStr, index) => (
                        <path
                            key={`outline-${index}`}
                            d={pathStr}
                            fill="none"
                            stroke="#0066CC"
                            strokeLinecap="round"
                            strokeLinejoin="round"
                            strokeMiterlimit={10}
                        />
                    ))}
                </g>
            </svg>

            {/* 3. Popup chi tiết bộ phận */}
            
        </div>
    );
};

// --- STYLES ---
const containerStyle: CSSProperties = {
    position: 'relative',
    width: '100%',
    height: '100%',
    minHeight: '520px',
    margin: '0 auto',
    display: 'flex',
    alignItems: 'center',
    justifyContent: 'center',
};

const popupStyle: CSSProperties = {
    position: 'absolute',
    top: '30%',
    left: '100%',
    width: '220px',
    background: 'white',
    padding: '15px',
    boxShadow: '0 4px 12px rgba(0,0,0,0.15)',
    borderRadius: '8px',
    border: '1px solid #eee',
    zIndex: 10,
};

const buttonStyle: CSSProperties = {
    background: '#0066CC',
    color: 'white',
    border: 'none',
    padding: '6px 12px',
    borderRadius: '4px',
    cursor: 'pointer',
};

export default MaleBack;